import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.saml2.core.Saml2Authentication;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistration;
import org.springframework.security.saml2.provider.service.web.authentication.logout.DelegatingSaml2LogoutRequestResolver;
import org.springframework.security.saml2.provider.service.web.authentication.logout.Saml2LogoutRequestResolver;
import org.springframework.security.web.SecurityFilterChain;

@SpringBootApplication
@EnableWebSecurity
public class SamlServiceProviderApplication {

    public static void main(String[] args) {
        SpringApplication.run(SamlServiceProviderApplication.class, args);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        return http
            .authorizeRequests(authorize -> authorize
                .antMatchers("/saml2/**").permitAll()
                .anyRequest().authenticated())
            .saml2Login(saml2Login -> saml2Login
                .relyingPartyRegistrationResolver(relyingPartyRegistrationResolver()))
            .saml2Logout(saml2Logout -> saml2Logout
                .logoutRequestResolver(logoutRequestResolver()))
            .build();
    }

    @Bean
    public RelyingPartyRegistration relyingPartyRegistration() {
        // Configure your Relying Party Registration here
        return RelyingPartyRegistration.withRegistrationId("default")
            .entityId("http://your-app.com/saml2/metadata")
            .singleSignOnServiceLocation("http://idp.example.com/sso/saml2")
            .singleLogoutServiceLocation("http://idp.example.com/slo/saml2")
            .credentialResolver(credentialResolver())
            .build();
    }

    @Bean
    public Saml2Authentication convertAssertionToAuthentication(Saml2Authentication authentication) {
        // Extract user attributes and create authenticated session here
        return authentication;
    }

    @Bean
    public DelegatingSaml2LogoutRequestResolver logoutRequestResolver() {
        List<Saml2LogoutRequestResolver> delegates = new ArrayList<>();
        // Add your Logout Request Resolvers here
        return new DelegatingSaml2LogoutRequestResolver(delegates);
    }
}